package com.hospital.management.validation;import com.hospital.management.model.PatientForm;import org.junit.jupiter.api.Test;import java.time.LocalDate;import static org.junit.jupiter.api.Assertions.*;
class PatientValidatorTest{private final PatientValidator v=new PatientValidator();@Test void validWithoutLogin(){assertFalse(v.validateCreate(f()).hasErrors());}@Test void validWithLogin(){PatientForm f=f();f.setCreateLoginAccount(true);f.setEmail("p@example.com");f.setUsername("patient1");f.setPassword("Strong@123");f.setConfirmPassword("Strong@123");assertFalse(v.validateCreate(f).hasErrors());}@Test void blankName(){PatientForm f=f();f.setFirstName("");assertTrue(v.validateCreate(f).getErrors().containsKey("firstName"));}@Test void futureBirth(){PatientForm f=f();f.setDateOfBirth(LocalDate.now().plusDays(1).toString());assertTrue(v.validateCreate(f).hasErrors());}@Test void invalidGender(){PatientForm f=f();f.setGender("X");assertTrue(v.validateCreate(f).hasErrors());}@Test void invalidBlood(){PatientForm f=f();f.setBloodGroup("X");assertTrue(v.validateCreate(f).hasErrors());}@Test void invalidPhone(){PatientForm f=f();f.setPhone("1");assertTrue(v.validateCreate(f).hasErrors());}@Test void invalidEmail(){PatientForm f=f();f.setEmail("bad");assertTrue(v.validateCreate(f).hasErrors());}@Test void weakPassword(){PatientForm f=login();f.setPassword("weak");assertTrue(v.validateCreate(f).hasErrors());}@Test void mismatch(){PatientForm f=login();f.setConfirmPassword("Other@123");assertTrue(v.validateCreate(f).hasErrors());}@Test void editBlankPassword(){PatientForm f=login();f.setCreateLoginAccount(false);f.setPassword("");f.setConfirmPassword("");assertFalse(v.validateEdit(f,true).hasErrors());}@Test void invalidStatus(){PatientForm f=f();f.setStatus("DELETED");assertTrue(v.validateCreate(f).hasErrors());}private PatientForm login(){PatientForm f=f();f.setCreateLoginAccount(true);f.setEmail("p@example.com");f.setUsername("patient1");f.setPassword("Strong@123");f.setConfirmPassword("Strong@123");return f;}private PatientForm f(){PatientForm f=new PatientForm();f.setPatientNumber("");f.setFirstName("Demo");f.setLastName("Patient");f.setDateOfBirth("1990-01-01");f.setGender("OTHER");f.setBloodGroup("O+");f.setPhone("9000000002");f.setEmail("");f.setStatus("ACTIVE");return f;}}
